import { handleSupabaseError, withRetry, withTimeout } from '@/lib'

try {
  const result = await withTimeout(
    withRetry(async () => {
      return await fetchAll('users', { filters: [...] })
    }, {
      retries: 3,
      backoff: 'exponential',
      delay: 1000,
    }),
    10000, // 10 second timeout
    'Query timed out'
  )
} catch (error) {
  const normalized = handleSupabaseError(error)
  if (normalized.code === 'rate_limit') {
    console.log(`Rate limited, reset at: ${normalized.resetAt}`)
  }
}

import { z, validateInput, validateOrFail, createValidator } from '@/lib'

// Define schema
const userSchema = z.object({
  name: z.string().min(2).max(100),
  email: z.string().email(),
  age: z.number().int().min(0).max(150).optional(),
  role: z.enum(['admin', 'member', 'guest']).default('member'),
})

// Safe validation
const result = validateInput(input, userSchema)
if (!result.valid) {
  console.log(result.errors)
}

// Strict validation (throws on failure)
const user = validateOrFail(input, userSchema)

// Reusable validator
const userValidator = createValidator(userSchema)
const parsed = userValidator.parse(input)

import { rateLimit, createRateLimiter } from '@/lib'

// Quick rate limit check
const status = await rateLimit(userId, {
  windowMs: 60000,
  maxRequests: 10,
})

if (!status.allowed) {
  throw new RateLimitError('Too many requests', {
    resetAt: status.resetAt,
  })
}

// Custom limiter for specific endpoint
const loginLimiter = createRateLimiter({
  windowMs: 300000, // 5 minutes
  maxRequests: 5,
  message: 'Too many login attempts',
})

await loginLimiter.consume(userId)
